import { Injectable } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class LocalStorageService {

  get<T>(key: string, defaultValue: T): T {
    try {
      const item = localStorage.getItem(key);
      return item !== null ? JSON.parse(item) as T : defaultValue;
    } catch {
      console.warn(`Failed to parse localStorage key "${key}", returning default`);
      return defaultValue;
    }
  }

  set<T>(key: string, value: T): void {
    try {
      localStorage.setItem(key, JSON.stringify(value));
    } catch (e) {
      console.error(`Failed to write to localStorage key "${key}"`, e);
    }
  }

  remove(key: string): void {
    localStorage.removeItem(key);
  }

  clear(): void {
    localStorage.clear();
  }
}

Key points: providedIn: 'root' makes it a singleton. Generic get<T> ensures type safety at call sites. Try-catch handles QuotaExceededError on set and corrupted JSON on get.

