function longestConsecutive(nums: number[]): number {
  const numSet = new Set(nums);
  let longest = 0;

  for (const num of numSet) {
    // Only start a sequence if num is the beginning (num-1 not in set)
    if (!numSet.has(num - 1)) {
      let current = num;
      let streak = 1;
      while (numSet.has(current + 1)) {
        current++;
        streak++;
      }
      longest = Math.max(longest, streak);
    }
  }
  return longest;
}

Why this is O(n): Each number is visited at most twice — once when iterating, once when extending a streak. The key insight is the (num - 1) check ensures we only start from sequence beginnings.

Time complexity: O(n).
Space complexity: O(n) for the set.

