function calculate(s: string): number {
  const stack: number[] = [];
  let currentNum = 0;
  let operator = '+';

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (ch >= '0' && ch <= '9') {
      currentNum = currentNum * 10 + Number(ch);
    }
    if (('+-*/'.includes(ch) && ch !== ' ') || i === s.length - 1) {
      switch (operator) {
        case '+': stack.push(currentNum); break;
        case '-': stack.push(-currentNum); break;
        case '*': stack.push(stack.pop()! * currentNum); break;
        case '/': stack.push(Math.trunc(stack.pop()! / currentNum)); break;
      }
      operator = ch;
      currentNum = 0;
    }
  }
  return stack.reduce((sum, val) => sum + val, 0);
}

Key insight: When encountering * or /, pop the last value from the stack and compute immediately. For + and -, just push the value (negated for -). Final sum gives the result.

Time complexity: O(n) — single pass.
Space complexity: O(n) for the stack.

