public List<String> getTopCities(List<Transaction> transactions, int year) {
    Map<String, Double> cityTotals = new HashMap<>();
    for (Transaction t : transactions) {
        if (t.getYear() == year && t.getAmount() > 0) {
            String city = t.getCity();
            if (cityTotals.containsKey(city)) {
                cityTotals.put(city, cityTotals.get(city) + t.getAmount());
            } else {
                cityTotals.put(city, t.getAmount());
            }
        }
    }
    List<Map.Entry<String, Double>> entries = new ArrayList<>(cityTotals.entrySet());
    entries.sort((a, b) -> Double.compare(b.getValue(), a.getValue()));
    List<String> result = new ArrayList<>();
    for (int i = 0; i < Math.min(3, entries.size()); i++) {
        result.add(entries.get(i).getKey());
    }
    return result;
}
