// 1. Eager Initialization
public class EagerSingleton {
    private static final EagerSingleton INSTANCE = new EagerSingleton();
    private EagerSingleton() {}
    public static EagerSingleton getInstance() { return INSTANCE; }
}
// Pros: Simple, thread-safe (JVM guarantees). Cons: Instance created even if never used.

// 2. Double-Checked Locking
public class DCLSingleton {
    private static volatile DCLSingleton instance; // volatile is crucial!
    private DCLSingleton() {}
    public static DCLSingleton getInstance() {
        if (instance == null) {
            synchronized (DCLSingleton.class) {
                if (instance == null) {
                    instance = new DCLSingleton();
                }
            }
        }
        return instance;
    }
}
// volatile prevents instruction reordering — without it, another thread
// could see a partially constructed object. The outer null check avoids
// synchronization after initialization.

// 3. Bill Pugh (Static Inner Class)
public class BillPughSingleton {
    private BillPughSingleton() {}
    private static class Holder {
        private static final BillPughSingleton INSTANCE = new BillPughSingleton();
    }
    public static BillPughSingleton getInstance() {
        return Holder.INSTANCE;
    }
}
// Lazy: Holder class is not loaded until getInstance() is called.
// Thread-safe: Class loading is inherently thread-safe.

