public interface StockObserver {
    void onPriceChange(String symbol, double oldPrice, double newPrice);
}

public class PriceAlertObserver implements StockObserver {
    private final String watchSymbol;
    private final double threshold;

    public PriceAlertObserver(String symbol, double threshold) {
        this.watchSymbol = symbol;
        this.threshold = threshold;
    }

    @Override
    public void onPriceChange(String symbol, double oldPrice, double newPrice) {
        if (symbol.equals(watchSymbol) && oldPrice < threshold && newPrice >= threshold) {
            System.out.printf("ALERT: %s crossed $%.2f (now $%.2f)%n", symbol, threshold, newPrice);
        }
    }
}

public class PriceLogObserver implements StockObserver {
    @Override
    public void onPriceChange(String symbol, double oldPrice, double newPrice) {
        double change = ((newPrice - oldPrice) / oldPrice) * 100;
        System.out.printf("[LOG] %s: $%.2f -> $%.2f (%.2f%%)%n", symbol, oldPrice, newPrice, change);
    }
}

public class StockExchange {
    private final Map<String, Double> prices = new HashMap<>();
    private final List<StockObserver> observers = new ArrayList<>();

    public void addObserver(StockObserver observer) { observers.add(observer); }
    public void removeObserver(StockObserver observer) { observers.remove(observer); }

    public void updatePrice(String symbol, double newPrice) {
        double oldPrice = prices.getOrDefault(symbol, 0.0);
        prices.put(symbol, newPrice);
        if (oldPrice != newPrice) {
            notifyObservers(symbol, oldPrice, newPrice);
        }
    }

    private void notifyObservers(String symbol, double oldPrice, double newPrice) {
        for (StockObserver observer : observers) {
            observer.onPriceChange(symbol, oldPrice, newPrice);
        }
    }
}

Key design decisions: Observer interface uses push model (data passed in notification). Subject manages observer lifecycle. Notifications only fire on actual changes. Loose coupling — StockExchange knows nothing about concrete observers.

import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Subject, Observable, of } from 'rxjs';
import { debounceTime, distinctUntilChanged, filter, switchMap, catchError, tap } from 'rxjs/operators';

export interface SearchResult {
  id: string;
  title: string;
}

@Injectable({ providedIn: 'root' })
export class SearchService {
  private searchSubject = new Subject<string>();
  private cache = new Map<string, SearchResult[]>();
  private cacheKeys: string[] = []; // track insertion order
  private readonly MAX_CACHE = 5;

  results$: Observable<SearchResult[]> = this.searchSubject.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    filter(term => term.length >= 2),
    switchMap(term => this.searchWithCache(term))
  );

  constructor(private http: HttpClient) {}

  search(term: string): void {
    this.searchSubject.next(term);
  }

  private searchWithCache(term: string): Observable<SearchResult[]> {
    if (this.cache.has(term)) {
      return of(this.cache.get(term)!);
    }
    return this.http.get<SearchResult[]>(`/api/search?q=${encodeURIComponent(term)}`).pipe(
      tap(results => this.addToCache(term, results)),
      catchError(() => of([]))
    );
  }

  private addToCache(term: string, results: SearchResult[]): void {
    if (this.cacheKeys.length >= this.MAX_CACHE) {
      const oldest = this.cacheKeys.shift()!;
      this.cache.delete(oldest);
    }
    this.cache.set(term, results);
    this.cacheKeys.push(term);
  }
}

Operator choices:
- debounceTime(300): Waits for user to stop typing, reduces API calls
- distinctUntilChanged(): Skips duplicate consecutive searches
- filter(length >= 2): Avoids meaningless short searches
- switchMap: Cancels in-flight HTTP requests when new term arrives (prevents race conditions)
- catchError inside switchMap: Error in one search doesn't break the stream
- tap for side-effect caching without altering the data flow

