// cart.component.ts (parent)
@Component({
  selector: 'app-cart',
  template: `
    <h2>Shopping Cart</h2>
    <app-cart-item
      *ngFor="let item of items; trackBy: trackById"
      [item]="item"
      (quantityChange)="onQuantityChange($event)"
      (remove)="onRemove($event)"
    />
    <div class="total">
      <strong>Total: {{ total | currency }}</strong>
    </div>
  `
})
export class CartComponent {
  items: CartItem[] = [];

  get total(): number {
    return this.items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  }

  onQuantityChange(event: { id: number; delta: number }): void {
    const item = this.items.find(i => i.id === event.id);
    if (item) {
      item.quantity = Math.max(1, item.quantity + event.delta);
      this.items = [...this.items]; // trigger OnPush change detection
    }
  }

  onRemove(id: number): void {
    this.items = this.items.filter(i => i.id !== id);
  }

  trackById(index: number, item: CartItem): number {
    return item.id;
  }
}

Key patterns: Unidirectional data flow — parent owns state, child only emits events. OnPush on child for performance. trackBy for efficient ngFor rendering. Immutable array update (spread) to trigger change detection.

import { HttpInterceptorFn, HttpErrorResponse } from '@angular/common/http';
import { inject } from '@angular/core';
import { Router } from '@angular/router';
import { catchError, finalize, retry, timer, tap, throwError } from 'rxjs';

export const authRetryInterceptor: HttpInterceptorFn = (req, next) => {
  const router = inject(Router);
  const authService = inject(AuthService);
  const loadingService = inject(LoadingService);

  // 1. Add auth header
  const token = authService.getToken();
  const authReq = token
    ? req.clone({ setHeaders: { Authorization: `Bearer ${token}` } })
    : req;

  // 2. Show loading after 200ms delay
  let loadingVisible = false;
  const loadingTimer = setTimeout(() => {
    loadingService.show();
    loadingVisible = true;
  }, 200);

  return next(authReq).pipe(
    // 3. Retry with exponential backoff (skip 401s)
    retry({
      count: 2,
      delay: (error: HttpErrorResponse, retryCount) => {
        if (error.status === 401 || error.status === 403) {
          return throwError(() => error); // don't retry auth errors
        }
        return timer(retryCount * 1000); // 1s, 2s
      }
    }),
    // 4. Handle 401
    catchError((error: HttpErrorResponse) => {
      if (error.status === 401) {
        authService.clearToken();
        router.navigate(['/auth/signin']);
      }
      return throwError(() => error);
    }),
    // Clean up loading spinner
    finalize(() => {
      clearTimeout(loadingTimer);
      if (loadingVisible) loadingService.hide();
    })
  );
};

// Register in app.config.ts:
// provideHttpClient(withInterceptors([authRetryInterceptor]))

Key points: Functional interceptor uses inject() instead of constructor DI. Retry skips 401/403 to avoid pointless retries on auth failures. finalize() ensures spinner is hidden even on error. Loading delay prevents spinner flash for fast requests.

