// 1. MyPick
type MyPick<T, K extends keyof T> = {
  [P in K]: T[P];
};

// 2. MyOmit
type MyOmit<T, K extends keyof T> = {
  [P in Exclude<keyof T, K>]: T[P];
};
// Alternative: MyPick<T, Exclude<keyof T, K>>

// 3. MyReadonly
type MyReadonly<T> = {
  readonly [P in keyof T]: T[P];
};

// 4. MyPartial
type MyPartial<T> = {
  [P in keyof T]?: T[P];
};

// 5. DeepReadonly
type DeepReadonly<T> = T extends Function
  ? T
  : T extends object
    ? { readonly [P in keyof T]: DeepReadonly<T[P]> }
    : T;

// Usage examples:
interface User {
  name: string;
  age: number;
  address: {
    street: string;
    city: string;
  };
}

type NameOnly = MyPick<User, 'name'>;           // { name: string }
type NoAge = MyOmit<User, 'age'>;               // { name: string; address: {...} }
type ReadonlyUser = MyReadonly<User>;            // all props readonly
type OptionalUser = MyPartial<User>;            // all props optional
type DeepRO = DeepReadonly<User>;               // address.street is also readonly

// MyPick<User, 'invalid'>;  // Compile error! 'invalid' not in keyof User

Key concepts: Mapped types iterate over keys. 'extends keyof T' constrains valid keys. Conditional types enable recursive type transformations. Exclude is a distributive conditional type.

