import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable } from 'rxjs';
import { map, distinctUntilChanged } from 'rxjs/operators';

export interface Todo {
  id: number;
  title: string;
  completed: boolean;
}

export type TodoFilter = 'all' | 'active' | 'completed';

interface TodoState {
  todos: Todo[];
  filter: TodoFilter;
  loading: boolean;
}

const initialState: TodoState = {
  todos: [],
  filter: 'all',
  loading: false
};

@Injectable({ providedIn: 'root' })
export class TodoStore {
  private state$ = new BehaviorSubject<TodoState>(initialState);
  private nextId = 1;

  // Selectors
  readonly todos$ = this.select(s => s.todos);
  readonly filter$ = this.select(s => s.filter);
  readonly loading$ = this.select(s => s.loading);
  readonly filteredTodos$ = this.state$.pipe(
    map(state => {
      switch (state.filter) {
        case 'active': return state.todos.filter(t => !t.completed);
        case 'completed': return state.todos.filter(t => t.completed);
        default: return state.todos;
      }
    })
  );
  readonly activeCount$ = this.todos$.pipe(
    map(todos => todos.filter(t => !t.completed).length)
  );

  // Actions
  addTodo(title: string): void {
    const state = this.state$.getValue();
    const newTodo: Todo = { id: this.nextId++, title, completed: false };
    this.state$.next({ ...state, todos: [...state.todos, newTodo] });
  }

  toggleTodo(id: number): void {
    const state = this.state$.getValue();
    this.state$.next({
      ...state,
      todos: state.todos.map(t =>
        t.id === id ? { ...t, completed: !t.completed } : t
      )
    });
  }

  removeTodo(id: number): void {
    const state = this.state$.getValue();
    this.state$.next({
      ...state,
      todos: state.todos.filter(t => t.id !== id)
    });
  }

  setFilter(filter: TodoFilter): void {
    const state = this.state$.getValue();
    this.state$.next({ ...state, filter });
  }

  private select<R>(selector: (state: TodoState) => R): Observable<R> {
    return this.state$.pipe(map(selector), distinctUntilChanged());
  }
}

// Component usage:
@Component({ ... })
export class TodoPageComponent {
  filteredTodos$ = this.store.filteredTodos$;
  activeCount$ = this.store.activeCount$;

  constructor(private store: TodoStore) {}

  onAdd(title: string) { this.store.addTodo(title); }
  onToggle(id: number) { this.store.toggleTodo(id); }
}

Key patterns: Single source of truth in BehaviorSubject. Immutable updates with spread operator. Selectors with distinctUntilChanged prevent unnecessary re-renders. Private BehaviorSubject ensures state can only change through defined actions.

