function lengthOfLongestSubstring(s: string): number {
  const charIndex = new Map<string, number>();
  let maxLen = 0;
  let left = 0;

  for (let right = 0; right < s.length; right++) {
    const ch = s[right];
    if (charIndex.has(ch) && charIndex.get(ch)! >= left) {
      left = charIndex.get(ch)! + 1;
    }
    charIndex.set(ch, right);
    maxLen = Math.max(maxLen, right - left + 1);
  }
  return maxLen;
}

Key insight: Instead of shrinking the window one character at a time, jump left to the position after the last occurrence of the duplicate character. The Map stores the most recent index of each character.

Time complexity: O(n) — single pass with the right pointer.
Space complexity: O(min(n, charset)) — the map stores at most one entry per unique character.

