import java.util.LinkedList;
import java.util.Queue;
import java.util.concurrent.locks.Condition;
import java.util.concurrent.locks.ReentrantLock;

public class BoundedBlockingQueue<T> {
    private final Queue<T> queue = new LinkedList<>();
    private final int capacity;
    private final ReentrantLock lock = new ReentrantLock();
    private final Condition notFull = lock.newCondition();
    private final Condition notEmpty = lock.newCondition();

    public BoundedBlockingQueue(int capacity) {
        this.capacity = capacity;
    }

    public void put(T item) throws InterruptedException {
        lock.lock();
        try {
            while (queue.size() == capacity) {
                notFull.await(); // block until space is available
            }
            queue.add(item);
            notEmpty.signal(); // wake up a waiting consumer
        } finally {
            lock.unlock();
        }
    }

    public T take() throws InterruptedException {
        lock.lock();
        try {
            while (queue.isEmpty()) {
                notEmpty.await(); // block until item is available
            }
            T item = queue.remove();
            notFull.signal(); // wake up a waiting producer
            return item;
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return queue.size();
        } finally {
            lock.unlock();
        }
    }
}

Why Condition over wait/notify:
1. Multiple conditions: notFull and notEmpty are separate — signal() wakes only the relevant waiting thread. With wait/notify, notifyAll() wakes ALL waiting threads.
2. Fairness: ReentrantLock(true) can enforce FIFO ordering.
3. tryLock/lockInterruptibly: More flexible locking options.
4. Always use while (not if) with await() — guards against spurious wakeups.

