// Interface
interface RateLimiter {
  isAllowed(clientId: string): boolean;
}

// 1. Fixed Window
class FixedWindowLimiter implements RateLimiter {
  private windows = new Map<string, { count: number; windowStart: number }>();

  constructor(private maxRequests: number, private windowMs: number) {}

  isAllowed(clientId: string): boolean {
    const now = Date.now();
    const window = this.windows.get(clientId);

    if (!window || now - window.windowStart >= this.windowMs) {
      this.windows.set(clientId, { count: 1, windowStart: now });
      return true;
    }
    if (window.count < this.maxRequests) {
      window.count++;
      return true;
    }
    return false;
  }
}

// 2. Sliding Window Log
class SlidingWindowLogLimiter implements RateLimiter {
  private logs = new Map<string, number[]>();

  constructor(private maxRequests: number, private windowMs: number) {}

  isAllowed(clientId: string): boolean {
    const now = Date.now();
    let timestamps = this.logs.get(clientId) || [];
    timestamps = timestamps.filter(t => now - t < this.windowMs);
    this.logs.set(clientId, timestamps);

    if (timestamps.length < this.maxRequests) {
      timestamps.push(now);
      return true;
    }
    return false;
  }
}

// 3. Token Bucket
class TokenBucketLimiter implements RateLimiter {
  private buckets = new Map<string, { tokens: number; lastRefill: number }>();

  constructor(
    private maxTokens: number,
    private refillRate: number, // tokens per second
  ) {}

  isAllowed(clientId: string): boolean {
    const now = Date.now();
    let bucket = this.buckets.get(clientId);

    if (!bucket) {
      this.buckets.set(clientId, { tokens: this.maxTokens - 1, lastRefill: now });
      return true;
    }

    const elapsed = (now - bucket.lastRefill) / 1000;
    bucket.tokens = Math.min(this.maxTokens, bucket.tokens + elapsed * this.refillRate);
    bucket.lastRefill = now;

    if (bucket.tokens >= 1) {
      bucket.tokens -= 1;
      return true;
    }
    return false;
  }
}

// Factory
function createRateLimiter(
  strategy: 'fixed' | 'sliding' | 'token',
  config: { maxRequests: number; windowMs?: number; refillRate?: number }
): RateLimiter {
  switch (strategy) {
    case 'fixed': return new FixedWindowLimiter(config.maxRequests, config.windowMs!);
    case 'sliding': return new SlidingWindowLogLimiter(config.maxRequests, config.windowMs!);
    case 'token': return new TokenBucketLimiter(config.maxRequests, config.refillRate!);
  }
}

Trade-offs:
- Fixed Window: O(1) memory per client, but allows burst at window boundaries (up to 2x rate).
- Sliding Window Log: Most precise, but O(n) memory per client where n = max requests. Expensive for high-rate limits.
- Token Bucket: O(1) memory, allows controlled bursts (up to maxTokens), smoothest rate limiting. Best for APIs.

Concurrency note: In production, use mutex/lock per client ID, or atomic operations. For distributed systems, use Redis with Lua scripts for atomicity.

