type ChangeLog = Map<string, { existed: boolean; value?: string }>;

class KVStore {
  private store = new Map<string, string>();
  private transactionStack: ChangeLog[] = [];

  get(key: string): string | undefined {
    return this.store.get(key);
  }

  set(key: string, value: string): void {
    this.recordChange(key);
    this.store.set(key, value);
  }

  delete(key: string): boolean {
    if (!this.store.has(key)) return false;
    this.recordChange(key);
    this.store.delete(key);
    return true;
  }

  begin(): void {
    this.transactionStack.push(new Map());
  }

  commit(): void {
    if (this.transactionStack.length === 0) {
      throw new Error('No active transaction');
    }
    const committed = this.transactionStack.pop()!;
    // Merge into parent transaction (if nested) so parent rollback works
    if (this.transactionStack.length > 0) {
      const parent = this.transactionStack[this.transactionStack.length - 1];
      for (const [key, prev] of committed) {
        if (!parent.has(key)) {
          parent.set(key, prev);
        }
      }
    }
  }

  rollback(): void {
    if (this.transactionStack.length === 0) {
      throw new Error('No active transaction');
    }
    const changes = this.transactionStack.pop()!;
    for (const [key, prev] of changes) {
      if (prev.existed) {
        this.store.set(key, prev.value!);
      } else {
        this.store.delete(key);
      }
    }
  }

  private recordChange(key: string): void {
    if (this.transactionStack.length === 0) return;
    const currentTx = this.transactionStack[this.transactionStack.length - 1];
    // Only record the FIRST change to this key in this transaction
    if (!currentTx.has(key)) {
      currentTx.set(key, {
        existed: this.store.has(key),
        value: this.store.get(key)
      });
    }
  }
}

// Usage:
const db = new KVStore();
db.set('a', '1');
db.begin();
db.set('a', '2');
db.begin();
db.set('a', '3');
db.rollback();    // a = '2'
db.commit();      // a = '2' (committed)

Key design decisions:
- Store is always up-to-date (reads are always O(1))
- Undo log only records FIRST change per key per transaction (subsequent changes don't need a new log entry)
- Commit merges into parent transaction so that a rollback of the parent also undoes committed nested changes
- All operations are O(1) average time

Space complexity: O(k) per transaction where k is unique keys modified.

