// --- Interfaces ---
export interface ValidationRule {
  validator: string;           // plugin name
  params?: Record<string, any>; // e.g., { min: 3, max: 50 }
  message?: string;            // custom message template
  async?: boolean;
}

export interface FieldConfig {
  name: string;
  validators: ValidationRule[];
}

export interface FormValidationConfig {
  fields: FieldConfig[];
  crossField?: ValidationRule[];  // validators that span multiple fields
}

export interface ValidatorPlugin {
  name: string;
  validate(value: any, params?: Record<string, any>): string | null;
}

export interface AsyncValidatorPlugin {
  name: string;
  validate(value: any, params?: Record<string, any>): Observable<string | null>;
}

// --- Injection Token ---
export const VALIDATOR_PLUGINS = new InjectionToken<ValidatorPlugin[]>('VALIDATOR_PLUGINS');
export const ASYNC_VALIDATOR_PLUGINS = new InjectionToken<AsyncValidatorPlugin[]>('ASYNC_VALIDATOR_PLUGINS');

// --- Built-in plugins ---
export const requiredValidator: ValidatorPlugin = {
  name: 'required',
  validate: (value) => (value == null || value === '') ? 'This field is required' : null
};

export const minLengthValidator: ValidatorPlugin = {
  name: 'minLength',
  validate: (value, params) => {
    if (!value || value.length < params!.min) {
      return `Must be at least ${params!.min} characters`;
    }
    return null;
  }
};

export const patternValidator: ValidatorPlugin = {
  name: 'pattern',
  validate: (value, params) => {
    if (value && !new RegExp(params!.regex).test(value)) {
      return params!.message || 'Invalid format';
    }
    return null;
  }
};

export const uniqueUsernameValidator: AsyncValidatorPlugin = {
  name: 'uniqueUsername',
  validate: (value, params) => {
    // In real implementation, inject HttpClient
    return of(value).pipe(
      delay(300),
      switchMap(v => inject(HttpClient).get<boolean>(`/api/users/check?username=${v}`)),
      map(taken => taken ? 'Username is already taken' : null),
      catchError(() => of(null))
    );
  }
};

// --- Validation Engine ---
@Injectable({ providedIn: 'root' })
export class ValidationEngine {
  private syncPlugins = new Map<string, ValidatorPlugin>();
  private asyncPlugins = new Map<string, AsyncValidatorPlugin>();

  constructor(
    @Inject(VALIDATOR_PLUGINS) @Optional() syncPlugins: ValidatorPlugin[] = [],
    @Inject(ASYNC_VALIDATOR_PLUGINS) @Optional() asyncPlugins: AsyncValidatorPlugin[] = []
  ) {
    syncPlugins.forEach(p => this.registerSync(p));
    asyncPlugins.forEach(p => this.registerAsync(p));
  }

  registerSync(plugin: ValidatorPlugin): void {
    this.syncPlugins.set(plugin.name, plugin);
  }

  registerAsync(plugin: AsyncValidatorPlugin): void {
    this.asyncPlugins.set(plugin.name, plugin);
  }

  buildFormGroup(config: FormValidationConfig, fb: FormBuilder): FormGroup {
    const controls: Record<string, any> = {};
    for (const field of config.fields) {
      const syncValidators = this.buildSyncValidators(field.validators.filter(v => !v.async));
      const asyncValidators = this.buildAsyncValidators(field.validators.filter(v => v.async));
      controls[field.name] = ['', { validators: syncValidators, asyncValidators }];
    }
    const group = fb.group(controls);
    if (config.crossField) {
      group.setValidators(this.buildCrossFieldValidators(config.crossField));
    }
    return group;
  }

  private buildSyncValidators(rules: ValidationRule[]): ValidatorFn[] {
    return rules.map(rule => {
      const plugin = this.syncPlugins.get(rule.validator);
      if (!plugin) throw new Error(`Unknown validator: ${rule.validator}`);
      return (control: AbstractControl): ValidationErrors | null => {
        const error = plugin.validate(control.value, rule.params);
        return error ? { [rule.validator]: this.formatMessage(error, rule) } : null;
      };
    });
  }

  private buildAsyncValidators(rules: ValidationRule[]): AsyncValidatorFn[] {
    return rules.map(rule => {
      const plugin = this.asyncPlugins.get(rule.validator);
      if (!plugin) throw new Error(`Unknown async validator: ${rule.validator}`);
      return (control: AbstractControl): Observable<ValidationErrors | null> => {
        return plugin.validate(control.value, rule.params).pipe(
          map(error => error ? { [rule.validator]: this.formatMessage(error, rule) } : null)
        );
      };
    });
  }

  private buildCrossFieldValidators(rules: ValidationRule[]): ValidatorFn {
    return (group: AbstractControl): ValidationErrors | null => {
      const errors: ValidationErrors = {};
      for (const rule of rules) {
        const plugin = this.syncPlugins.get(rule.validator);
        if (plugin) {
          const error = plugin.validate(group.value, rule.params);
          if (error) errors[rule.validator] = error;
        }
      }
      return Object.keys(errors).length ? errors : null;
    };
  }

  private formatMessage(error: string, rule: ValidationRule): string {
    if (!rule.message) return error;
    let msg = rule.message;
    if (rule.params) {
      Object.entries(rule.params).forEach(([key, val]) => {
        msg = msg.replace(`{{${key}}}`, String(val));
      });
    }
    return msg;
  }
}

// --- Component Usage ---
@Component({ ... })
export class RegistrationComponent implements OnInit {
  form!: FormGroup;

  constructor(
    private fb: FormBuilder,
    private validationEngine: ValidationEngine,
    private http: HttpClient
  ) {}

  ngOnInit() {
    this.http.get<FormValidationConfig>('/api/forms/registration').subscribe(config => {
      this.form = this.validationEngine.buildFormGroup(config, this.fb);
    });
  }
}

// --- Module Registration (lazy-loaded module adds custom validators) ---
@NgModule({
  providers: [
    { provide: VALIDATOR_PLUGINS, useValue: customDomainValidator, multi: true }
  ]
})
export class CustomFeatureModule {}

Architecture benefits:
1. Validators are decoupled from forms — JSON config drives validation
2. Lazy modules register domain-specific validators via multi-providers
3. Sync and async handled uniformly
4. Cross-field validation integrated at FormGroup level
5. Message templates allow i18n and customization
6. Full integration with Angular's ReactiveFormsModule validation pipeline

// --- Core Interfaces ---
@FunctionalInterface
public interface Stage<I, O> {
    CompletableFuture<O> process(I input);

    default <R> Stage<I, R> andThen(Stage<O, R> next) {
        return input -> this.process(input).thenCompose(next::process);
    }
}

public interface Filter<T> extends Stage<T, T> {
    boolean test(T input);

    @Override
    default CompletableFuture<T> process(T input) {
        return test(input)
            ? CompletableFuture.completedFuture(input)
            : CompletableFuture.failedFuture(new FilteredException(input));
    }
}

public record DeadLetterRecord<T>(T record, Throwable error, int retryCount, Instant timestamp) {}

// --- Pipeline Builder ---
public class Pipeline<I> {
    private final BlockingQueue<I> inputQueue;
    private final List<StageWrapper<?, ?>> stages = new ArrayList<>();
    private final BlockingQueue<DeadLetterRecord<?>> deadLetterQueue;
    private final ExecutorService executor;
    private final int maxRetries;

    private Pipeline(int bufferSize, int maxRetries) {
        this.inputQueue = new ArrayBlockingQueue<>(bufferSize); // backpressure!
        this.deadLetterQueue = new LinkedBlockingQueue<>();
        this.executor = Executors.newVirtualThreadPerTaskExecutor();
        this.maxRetries = maxRetries;
    }

    public static <I> PipelineBuilder<I, I> from(Source<I> source) {
        return new PipelineBuilder<>(source);
    }

    // --- Builder (fluent API) ---
    public static class PipelineBuilder<I, C> {
        private final Source<I> source;
        private final List<Stage<?, ?>> stages = new ArrayList<>();
        private int bufferSize = 1000;
        private int maxRetries = 3;

        PipelineBuilder(Source<I> source) { this.source = source; }

        @SuppressWarnings("unchecked")
        public <O> PipelineBuilder<I, O> transform(Stage<C, O> stage) {
            stages.add(stage);
            return (PipelineBuilder<I, O>) this;
        }

        public PipelineBuilder<I, C> filter(Predicate<C> predicate) {
            stages.add((Stage<C, C>) input ->
                predicate.test(input)
                    ? CompletableFuture.completedFuture(input)
                    : CompletableFuture.failedFuture(new FilteredException(input))
            );
            return this;
        }

        public PipelineBuilder<I, C> validate(Predicate<C> validator, String errorMsg) {
            stages.add((Stage<C, C>) input -> {
                if (!validator.test(input)) {
                    return CompletableFuture.failedFuture(new ValidationException(errorMsg));
                }
                return CompletableFuture.completedFuture(input);
            });
            return this;
        }

        public BranchBuilder<I, C> branch(Predicate<C> condition) {
            return new BranchBuilder<>(this, condition);
        }

        public PipelineBuilder<I, C> withBackpressure(int bufferSize) {
            this.bufferSize = bufferSize;
            return this;
        }

        public PipelineBuilder<I, C> withRetries(int maxRetries) {
            this.maxRetries = maxRetries;
            return this;
        }

        public Pipeline<I> to(Sink<C> sink) {
            stages.add((Stage<C, Void>) input -> {
                sink.accept(input);
                return CompletableFuture.completedFuture(null);
            });
            return build();
        }

        private Pipeline<I> build() { /* wire everything together */ }
    }

    // --- Execution with error handling ---
    @SuppressWarnings("unchecked")
    private <T> void processRecord(T record, int stageIndex) {
        if (stageIndex >= stages.size()) return;
        StageWrapper<T, ?> wrapper = (StageWrapper<T, ?>) stages.get(stageIndex);

        wrapper.stage.process(record)
            .thenAccept(result -> processRecord(result, stageIndex + 1))
            .exceptionally(error -> {
                if (error.getCause() instanceof FilteredException) {
                    return null; // filtered records are silently dropped
                }
                handleError(record, error, stageIndex);
                return null;
            });
    }

    private <T> void handleError(T record, Throwable error, int stageIndex) {
        DeadLetterRecord<T> dlr = new DeadLetterRecord<>(record, error, 1, Instant.now());
        deadLetterQueue.add(dlr);
        // Retry logic could re-enqueue after delay
    }

    public void start() {
        executor.submit(() -> {
            // Source produces into inputQueue (backpressure via blocking put)
            // Consumer thread pulls and processes
        });
    }
}

// --- Real-world example ---
Pipeline<UserEvent> pipeline = Pipeline
    .<UserEvent>from(kafkaSource)
    .filter(event -> event.getType() == EventType.REGISTRATION)
    .validate(event -> event.getEmail() != null, "Email is required")
    .transform(event -> enrichWithGeoData(event))       // async HTTP call
    .transform(event -> normalizePhoneNumber(event))    // sync transform
    .branch(event -> event.isPremium())
        .ifTrue(premiumSink)
        .ifFalse(standardSink)
    .withBackpressure(5000)
    .withRetries(3)
    .to(databaseSink);

pipeline.start();

Comparison with Reactive Streams:
- This framework is simpler and more explicit — good for team learning
- Reactive Streams (Reactor/RxJava) provide better backpressure (pull-based vs our push-with-blocking)
- Reactive Streams have richer operator ecosystem (buffer, window, merge, zip)
- Our approach: easier to debug (stack traces are readable), CompletableFuture is standard Java
- For production at scale, prefer Reactor/RxJava or Kafka Streams. This pattern works well for moderate-throughput application-level pipelines.

function countNumbers(arr: number[]): { positive: number; negative: number; zero: number } {
  return arr.reduce((acc, num) => {
    if (num > 0) acc.positive++;
    else if (num < 0) acc.negative++;
    else acc.zero++;
    return acc;
  }, { positive: 0, negative: 0, zero: 0 });
}

Time complexity: O(n) where n is the array length. Space complexity: O(1) since we only store three counters. Alternative: could use filter().length for each category but that traverses the array three times.

